import React from 'react';
import { useTheme } from '../ThemeContext';
import { TrendingUp } from 'lucide-react';

export function SalaryCard() {
  const { theme } = useTheme();
  const netSalary = 4250;
  const gross = 5600;
  const tax = gross - netSalary;

  const breakdown = [
    { label: 'Gross salary', value: `$${gross.toLocaleString()}`, color: 'text-dash-text' },
    { label: 'Income tax', value: `-$${tax.toLocaleString()}`, color: 'text-red-400' },
    { label: 'Net salary', value: `$${netSalary.toLocaleString()}`, color: 'text-dash-primary' },
  ];

  return (
    <div className="bg-dash-card border border-dash-border rounded-xl p-5 flex flex-col gap-4 transition-colors duration-200">
      <div className="flex items-center justify-between">
        <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Salary</h3>
        <span className="text-xs text-dash-text-muted">This month</span>
      </div>

      <div className="flex items-end gap-2">
        <p className="text-dash-text" style={{ fontSize: '30px', fontWeight: 700, lineHeight: 1 }}>
          ${netSalary.toLocaleString()}
        </p>
        <div className="flex items-center gap-1 mb-1 text-emerald-400" style={{ fontSize: '12px' }}>
          <TrendingUp size={14} />
          <span>+2.5%</span>
        </div>
      </div>

      <div className="space-y-2">
        {breakdown.map((item) => (
          <div key={item.label} className="flex items-center justify-between">
            <span className="text-dash-text-muted" style={{ fontSize: '12px' }}>{item.label}</span>
            <span className={item.color} style={{ fontSize: '13px', fontWeight: 500 }}>{item.value}</span>
          </div>
        ))}
      </div>

      <div className="h-px bg-dash-border" />

      <div className="flex items-center justify-between">
        <span className="text-dash-text-muted" style={{ fontSize: '12px' }}>Next payment</span>
        <span className="text-dash-text" style={{ fontSize: '12px', fontWeight: 500 }}>
          {new Date(new Date().getFullYear(), new Date().getMonth() + 1, 1).toLocaleDateString('en-US', {
            month: 'short', day: 'numeric',
          })}
        </span>
      </div>
    </div>
  );
}
